-- ============================================================
-- DELETE ALL TEST SEED DATA
-- Run in Supabase SQL Editor to clean up test users
-- Handles both old (a000...) and new (b000...) seed user IDs
-- ============================================================

-- Delete in order: children first, then parents (respects foreign keys)

-- 1. Messages in conversations involving seed users
DELETE FROM messages WHERE conversation_id IN (
  SELECT id FROM conversations WHERE participants && ARRAY[
    'b0000000-0000-0000-0000-000000000001'::uuid,
    'b0000000-0000-0000-0000-000000000002'::uuid,
    'b0000000-0000-0000-0000-000000000003'::uuid,
    'b0000000-0000-0000-0000-000000000004'::uuid,
    'b0000000-0000-0000-0000-000000000005'::uuid,
    'b0000000-0000-0000-0000-000000000006'::uuid,
    'b0000000-0000-0000-0000-000000000007'::uuid,
    'b0000000-0000-0000-0000-000000000008'::uuid,
    'b0000000-0000-0000-0000-000000000009'::uuid,
    'b0000000-0000-0000-0000-000000000010'::uuid
  ]
);

-- 2. Conversations involving seed users
DELETE FROM conversations WHERE participants && ARRAY[
  'b0000000-0000-0000-0000-000000000001'::uuid,
  'b0000000-0000-0000-0000-000000000002'::uuid,
  'b0000000-0000-0000-0000-000000000003'::uuid,
  'b0000000-0000-0000-0000-000000000004'::uuid,
  'b0000000-0000-0000-0000-000000000005'::uuid,
  'b0000000-0000-0000-0000-000000000006'::uuid,
  'b0000000-0000-0000-0000-000000000007'::uuid,
  'b0000000-0000-0000-0000-000000000008'::uuid,
  'b0000000-0000-0000-0000-000000000009'::uuid,
  'b0000000-0000-0000-0000-000000000010'::uuid
];

